"""Hadamard transform utilities and pre-computed Hadamard matrices.

Provides CUDA-compatible Hadamard transforms for rotation preprocessing.
Uses ``fast_hadamard_transform`` when available, falling back to a pure
PyTorch butterfly implementation.

This code is based on QuaRot(https://github.com/spcl/QuaRot/tree/main/quarot)
Licensed under Apache License 2.0.
Adapted from https://github.com/Cornell-RelaxML/quip-sharp/blob/main/lib/utils/matmul_had.py

Copyright 2025-2026 Fujitsu Ltd.

Author: Yusei Kawakami
"""

import torch

try:
    from fast_hadamard_transform import hadamard_transform as _fast_hadamard_transform

    _HAS_FAST_HADAMARD = True
except ImportError:
    _HAS_FAST_HADAMARD = False


def _hadamard_transform_fallback(X):
    """Pure-PyTorch butterfly Hadamard transform (fallback when ``fast_hadamard_transform`` is unavailable).

    Args:
        X: Input tensor whose last dimension is a power of 2.

    Returns:
        torch.Tensor: Unnormalised Hadamard-transformed ``X`` with the same shape.
    """
    n = X.shape[-1]
    output = X
    m = 1
    while m < n:
        output = output.view(*output.shape[:-1], n // (2 * m), 2 * m)
        left, right = output[..., :, :m], output[..., :, m:]
        combined = torch.cat([left + right, left - right], dim=-1)
        output = combined.view(*output.shape[:-2], n)
        m *= 2
    return output


class HadamardTransform(torch.autograd.Function):
    """Autograd-compatible unnormalised Hadamard transform.

    Both forward and backward apply the same Hadamard transform.
    This is mathematically correct because the Hadamard matrix is
    symmetric and orthogonal (up to scaling), so the Jacobian transpose
    is the transform itself.

    When ``fast_hadamard_transform`` is available **and** the input
    resides on a CUDA device, the CUDA kernel is used.  CPU tensors
    always use the pure-PyTorch fallback.  Float64 inputs are cast to
    float32 for the CUDA kernel (which only accepts fp16/bf16/fp32) and
    cast back afterwards.
    """

    @staticmethod
    def forward(ctx, u):
        if _HAS_FAST_HADAMARD and u.is_cuda:
            if u.dtype == torch.float64:
                return _fast_hadamard_transform(u.float()).to(torch.float64)
            return _fast_hadamard_transform(u)
        return _hadamard_transform_fallback(u)

    @staticmethod
    def backward(ctx, grad):
        if _HAS_FAST_HADAMARD and grad.is_cuda:
            if grad.dtype == torch.float64:
                return _fast_hadamard_transform(grad.float()).to(torch.float64)
            return _fast_hadamard_transform(grad)
        return _hadamard_transform_fallback(grad)


def get_hadK(n, transpose=False):
    """Return a pre-computed Hadamard kernel and block size for dimension *n*.

    Checks pre-computed Hadamard sizes in descending order and returns the
    largest ``K`` that divides ``n`` with ``n / K`` being a power of 2.

    Args:
        n: Target dimension (must be expressible as ``K * 2^m`` for a
            supported ``K``; otherwise ``n`` itself must be a power of 2).
        transpose: If True, return the transposed kernel.

    Returns:
        tuple: ``(hadK, K)`` where ``hadK`` is the ``(K, K)`` Hadamard tensor
        (or ``None`` when ``K == 1``) and ``K`` is the block size.
    """
    hadK, K = None, None
    if n % 172 == 0:  # llama-2-7b up
        assert is_pow2(n // 172)

        K = 172
        hadK = get_had172().T if transpose else get_had172()
    elif n % 156 == 0:  # llama-1-30b 3x hidden
        assert is_pow2(n // 156)

        K = 156
        hadK = get_had156().T if transpose else get_had156()
    elif n % 140 == 0:  # llama-1-30b intermediate
        assert is_pow2(n // 140)

        K = 140
        hadK = get_had140().T if transpose else get_had140()
    elif n % 108 == 0:  # llama-1-13b intermediate
        assert is_pow2(n // 108)

        K = 108
        hadK = get_had108().T if transpose else get_had108()
    elif n % 100 == 0:  # Qwen3-32B intermediate
        assert is_pow2(n // 100)

        K = 100
        hadK = get_had100().T if transpose else get_had100()
    elif n % 76 == 0:  # Qwen3-4B intermediate
        assert is_pow2(n // 76)

        K = 76
        hadK = get_had76().T if transpose else get_had76()
    elif n % 68 == 0:  # Qwen3-14B intermediate
        assert is_pow2(n // 68)

        K = 68
        hadK = get_had68().T if transpose else get_had68()
    elif n % 60 == 0:  # llama-1-13b 3x hidden
        assert is_pow2(n // 60)

        K = 60
        hadK = get_had60().T if transpose else get_had60()
    elif n % 52 == 0:  # llama-1-13b 1x hidden
        assert is_pow2(n // 52)

        K = 52
        hadK = get_had52().T if transpose else get_had52()
    elif n % 44 == 0:
        assert is_pow2(n // 44)

        K = 44
        hadK = get_had44().T if transpose else get_had44()
    elif n % 40 == 0:
        assert is_pow2(n // 40)

        K = 40
        hadK = get_had40().T if transpose else get_had40()
    elif n % 36 == 0:
        assert is_pow2(n // 36)

        K = 36
        hadK = get_had36().T if transpose else get_had36()
    elif n % 28 == 0:
        assert is_pow2(n // 28)

        K = 28
        hadK = get_had28().T if transpose else get_had28()
    elif n % 20 == 0:
        assert is_pow2(n // 20)

        K = 20
        hadK = get_had20().T if transpose else get_had20()
    elif n % 12 == 0:
        assert is_pow2(n // 12)

        K = 12
        hadK = get_had12().T if transpose else get_had12()
    else:
        assert is_pow2(n), f"n={n} is not a power of 2"

        K = 1

    return hadK, K


def matmul_hadU_cuda(X, hadK, K):
    """Normalised Hadamard transform using ``HadamardTransform`` autograd op.

    Works on both CUDA and CPU (uses ``fast_hadamard_transform`` CUDA
    extension when available, otherwise falls back to pure PyTorch).

    Args:
        X: Input tensor whose last dimension equals ``K * 2^m``.
        hadK: Pre-computed ``(K, K)`` Hadamard kernel from ``get_hadK``, or
            ``None`` when ``K == 1``.
        K: Block size returned by ``get_hadK``.

    Returns:
        torch.Tensor: Hadamard-transformed ``X``, scaled by ``1 / sqrt(n)``.
    """
    n = X.shape[-1]
    if K == 1:
        return HadamardTransform.apply(X.contiguous()) / torch.tensor(n).sqrt()
    input = X.view(-1, K, n // K)
    input = HadamardTransform.apply(input.contiguous()) / torch.tensor(n).sqrt()
    input = hadK.to(input.device).to(input.dtype) @ input
    return input.reshape(X.shape)


def is_pow2(n):
    """Check whether *n* is a positive power of 2."""
    return (n & (n - 1) == 0) and (n > 0)


